+            .get("logical_stream_owner_id")
+            .and_then(Value::as_str)
+            .is_some();
+        let has_fence = entry
+            .get("cancellation_fence")
+            .is_some_and(Value::is_object);
+        if has_stream_owner && has_fence {
+            Some(entry.clone())
+        } else {
+            None
+        }
+    })
